import{_ as t,o as a,c as o,ae as i}from"./chunks/framework.B6gjLfeO.js";const u=JSON.parse('{"title":"Links Page (New)","description":"","frontmatter":{"title":"Links Page (New)","slug":"links-page-new"},"headers":[],"relativePath":"marketer-hub/links-page-new.md","filePath":"marketer-hub/links-page-new.md"}'),n={name:"marketer-hub/links-page-new.md"};function r(l,e,s,d,c,h){return a(),o("div",null,[...e[0]||(e[0]=[i('<h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>Use the <strong>Links</strong> page to build, manage, and deploy links at scale through a dedicated interface in Branch. It also provides enhanced governance and data reporting on your Branch Links. Additionally, you get capabilities like template creation, export access, search, and filters.</p><h2 id="manager" tabindex="-1">Manager <a class="header-anchor" href="#manager" aria-label="Permalink to &quot;Manager&quot;">​</a></h2><p>The <strong>Links</strong> page allows you to easily organize and view all of your Branch Short Links and Ad Links in one place.</p><p>Here you&#39;ll be able to search, filter, export, and bulk publish Branch Links.</p><h4 id="create-links" tabindex="-1">Create links <a class="header-anchor" href="#create-links" aria-label="Permalink to &quot;Create links&quot;">​</a></h4><p>For full guides on creating Branch Links, read the following articles:</p><ul><li><a href="./create-quick-links.html">Create Web Links</a></li><li><a href="./create-app-links.html">Create App Links</a></li><li><a href="./ad-links.html">Create Ad Links</a></li></ul><h3 id="search-and-filters" tabindex="-1">Search and filters <a class="header-anchor" href="#search-and-filters" aria-label="Permalink to &quot;Search and filters&quot;">​</a></h3><p>You can find the links you need using the search bar to search by title or URL.</p><p>You can also apply the following filters to find and organize links:</p><table tabindex="0"><thead><tr><th>Filter</th><th>Description</th></tr></thead><tbody><tr><td>Archived</td><td>Filter for only archived or deleted Branch Links.</td></tr><tr><td>Unique</td><td>Filter for showing analytics unique to a user. For example, if 1 user clicks 100 times, it will count as 1. There is no concept of &quot;unique revenue&quot;; &quot;revenue&quot; is always the sum of all purchase events.</td></tr><tr><td>Link Analytics Window</td><td>Filter to only show Branch Links with attribution in a specific window.</td></tr><tr><td>Link Created Window</td><td>Filter to only show Branch Links created within a specific window.</td></tr><tr><td>Campaign</td><td>Filter for specific campaign names. Dropdown options are set when you create the Branch Link.</td></tr><tr><td>Feature</td><td>Filter for specific feature names. Dropdown options are set when you create the Branch Link.</td></tr><tr><td>Channel</td><td>Filter for specific channel names. Dropdown options are set when you create the Branch Link.</td></tr><tr><td>Tags</td><td>Filter for specific tags. Dropdown options are set when you create the Branch Link.</td></tr></tbody></table><h3 id="bulk-link-tools" tabindex="-1">Bulk link tools <a class="header-anchor" href="#bulk-link-tools" aria-label="Permalink to &quot;Bulk link tools&quot;">​</a></h3><p>When you click the <strong>Create Bulk Links</strong> button, you will be prompted to select a Link Template or upload a CSV to create bulk links. Once you select, you can begin creating standardized links in bulk, and once you&#39;re done, you can copy and/or export all links.</p><p>You can:</p><ul><li>Add and edit links in bulk.</li><li>Upload a CSV for bulk link creation.</li><li>Export a CSV of both link attributes and links.</li><li>Archive links.</li><li>Delete links.</li></ul><h3 id="analytics" tabindex="-1">Analytics <a class="header-anchor" href="#analytics" aria-label="Permalink to &quot;Analytics&quot;">​</a></h3><p>View your Branch Link performance through a report similar to Branch&#39;s <a href="./dashboard-reports.html">Events/Performance Table</a> on the <strong>Links</strong> page. It has the same column customizability and sorting for your measurement but specific to your Ad Links and Short Links.</p><div class="info custom-block"><p class="custom-block-title">Note</p><p>The Activation product only includes the <strong>Clicks</strong> metric.</p></div><h4 id="individual-link-stats" tabindex="-1">Individual link stats <a class="header-anchor" href="#individual-link-stats" aria-label="Permalink to &quot;Individual link stats&quot;">​</a></h4><p>You can access detailed statistics for your individual Branch Links on the <strong>Links</strong> page.</p><p>Select the three-dot icon in the row of the link you are interested in, then click on the <strong>Analysis</strong> option from the drop-down menu that opens. This will take you to a page where the <code>link id</code> has already been set for you for that particular link. You will also see a click flow count, broken out by operating system.</p><h2 id="templates" tabindex="-1">Templates <a class="header-anchor" href="#templates" aria-label="Permalink to &quot;Templates&quot;">​</a></h2><p>Link Templates are a way to apply specific standardizations to Branch Link you create in Branch. Read our <a href="./link-templates.html">Link Templates</a> article for more information.</p><h2 id="folders" tabindex="-1">Folders <a class="header-anchor" href="#folders" aria-label="Permalink to &quot;Folders&quot;">​</a></h2><p>You can use folders to organize links and enforce template requirements.</p><div class="info custom-block"><p class="custom-block-title">Note</p><p>Previously created Collections will now be viewable as folders.</p></div><h3 id="create-a-folder" tabindex="-1">Create a folder <a class="header-anchor" href="#create-a-folder" aria-label="Permalink to &quot;Create a folder&quot;">​</a></h3><p>Complete the following instructions to create a folder:</p><ol><li>In Branch, select <strong>Campaigns</strong> &gt; <strong>Links</strong>.</li><li>Select <strong>Create</strong> in the top-right corner of the page.</li><li>Select <strong>Folder</strong> from the drop-down menu that appears.</li><li>Enter a name for the folder.</li><li>Select whether you want a template to be associated with this folder. This will require that all links in this folder adhere to this template.</li><li>Select <strong>Save changes</strong>.</li></ol><p>Your created folder will now be viewable on the <strong>Links</strong> page and while creating a link.</p><h3 id="view-folders" tabindex="-1">View folders <a class="header-anchor" href="#view-folders" aria-label="Permalink to &quot;View folders&quot;">​</a></h3><p>By default, the <strong>Links</strong> page displays all of your created links.</p><p>Complete the following instructions to view a specific folder:</p><ol><li>In Branch, select <strong>Campaigns</strong> &gt; <strong>Links</strong>.</li><li>Select up-and-down arrow icon next to <strong>All Links</strong> at the top-left corner of the page.</li><li>From here, you can search or scroll through the list of folders.</li><li>Select the folder you want to open.</li></ol><h3 id="add-an-existing-link-to-a-folder" tabindex="-1">Add an existing link to a folder <a class="header-anchor" href="#add-an-existing-link-to-a-folder" aria-label="Permalink to &quot;Add an existing link to a folder&quot;">​</a></h3><p>Complete the following instructions to add an existing link to a folder:</p><ol><li>In Branch, select <strong>Campaigns</strong> &gt; <strong>Links</strong>.</li><li>Select the three-dot icon on the right side of the link you want to add to a folder.</li><li>Select <strong>Move</strong> from the drop-down menu that appears.</li><li>From here, you can search or scroll through the list of folders.</li><li>Select the folder you want to add the link to.</li><li>Select <strong>Save changes</strong>.</li></ol><div class="info custom-block"><p class="custom-block-title">Note</p><p>If a folder has a template associated with it, you can only add links that have been created with that template to that folder.</p></div><h3 id="remove-a-link-from-a-folder" tabindex="-1">Remove a link from a folder <a class="header-anchor" href="#remove-a-link-from-a-folder" aria-label="Permalink to &quot;Remove a link from a folder&quot;">​</a></h3><p>Complete the following instructions to remove a link from a folder:</p><ol><li>In Branch, select <strong>Campaigns</strong> &gt; <strong>Links</strong>.</li><li>Select the three-dot icon on the right side of the link you want to add to a folder.</li><li>Select <strong>Move</strong> from the drop-down menu that appears.</li><li>Select the <strong>Folder</strong> drop-down menu and select <strong>Remove link from folder</strong>.</li><li>Select <strong>Save changes</strong>.</li></ol>',42)])])}const f=t(n,[["render",r]]);export{u as __pageData,f as default};
